INSERT INTO passage_questions (id, passage_id, question_number, question_type, question_text, explanation, correct_choice) VALUES
(229, 77, 1, 'comprehension', 'According to the passage, what is a key characteristic of quantum entanglement?', '第2段落で、もつれた粒子の一方を測定すると、距離に関係なく相手の状態が瞬時に決定されると説明されている。ただし、これは光速を超える通信を可能にするものではないとも明記されている。選択肢1がこの記述に最も合致する。', 1),
(230, 77, 2, 'comprehension', 'What does the passage suggest about the current state of quantum computing development?', '第4段落で、キュービットは極めて不安定（precarious）で、進歩は「incremental rather than revolutionary」（革命的というより漸進的）であると述べられている。第5段落では、勢いが増していることも述べられている。選択肢3がこの二面性を最もよく捉えている。', 3),
(231, 77, 3, 'fill_in_blank', 'Choose the best option to fill in the blank [BLANK] in the passage.', '空所は第4段落の最後にあり、懐疑論者の主張が入る。文脈として、キュービットの不安定さやエラー訂正の困難さが述べられた後であり、進歩が漸進的であることが言及されている。選択肢2「truly fault-tolerant quantum computers remain decades away, if they are achievable at all」（真に耐障害性のある量子コンピュータは実現可能だとしても数十年先）が最も文脈に合う。', 2);
INSERT INTO question_choices (question_id, choice_number, choice_text) VALUES
(229, 1, 'Measuring one particle in an entangled pair instantaneously determines the state of its partner, regardless of the distance between them.'),
(229, 2, 'Entangled particles can transmit information faster than the speed of light, enabling instant communication across galaxies.'),
(229, 3, 'Entanglement occurs only under laboratory conditions and cannot be replicated in natural environments.'),
(229, 4, 'The phenomenon was universally accepted by physicists from the moment it was first proposed in 1935.'),
(230, 1, 'Quantum computers have already replaced classical supercomputers in most scientific research facilities worldwide.'),
(230, 2, 'The fundamental technical challenges have been fully resolved, and commercial quantum computers are now widely available.'),
(230, 3, 'While meaningful progress has been made and investment is growing, significant technical hurdles such as decoherence remain to be overcome.'),
(230, 4, 'Research into quantum computing has stalled due to a lack of government funding and private sector interest.'),
(231, 1, 'quantum entanglement is merely a theoretical curiosity with no real-world applications whatsoever'),
(231, 2, 'truly fault-tolerant quantum computers remain decades away, if they are achievable at all'),
(231, 3, 'classical computers have already reached their maximum processing capacity and cannot be further improved'),
(231, 4, 'the environmental impact of cooling systems for quantum computers makes the technology unsustainable');
